import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Checkbox, Tooltip, icon } from 'decantr/components';

code.example:
function SimplePermissionMatrix({ roles, permissions, values, onChange }) {
  const { table, thead, tbody, tr, th, td, div, span } = tags;

  return table({ class: css('_w[full] _border _r2 _overflow[hidden] _bordercollapse[collapse]') },
    thead({},
      tr({ class: css('_bg[var(--surface-raised)]') },
        th({ class: css('_p3 _textleft _textsm _fontmedium _borderB') }, 'Permission'),
        ...roles.map(role =>
          th({ class: css('_p3 _textcenter _textsm _fontmedium _borderB _w[100px]') },
            role.name
          )
        )
      )
    ),
    tbody({},
      ...permissions.map(perm =>
        tr({ class: css('_hover:bg[var(--surface-raised)/50]') },
          td({ class: css('_p3 _borderB') },
            div({ class: css('_flex _aic _gap2') },
              span({ class: css('_textsm') }, perm.name),
              perm.description ? Tooltip({ content: perm.description },
                icon('info', { size: '14', class: css('_fgmuted') })
              ) : null
            )
          ),
          ...roles.map(role =>
            td({ class: css('_p3 _textcenter _borderB') },
              role.locked ? icon(
                values[role.id]?.[perm.id] ? 'check' : 'x',
                { size: '16', class: css(values[role.id]?.[perm.id] ? '_fg[var(--success)]' : '_fgmuted _opacity50') }
              ) : Checkbox({
                checked: values[role.id]?.[perm.id] || false,
                onChange: (e) => onChange(role.id, perm.id, e.target.checked)
              })
            )
          )
        )
      )
    )
  );
}

