import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Button, Checkbox, Tooltip, icon } from 'decantr/components';

code.example:
function GranularPermissionMatrix({ roles, permissionCategories, values, onChange, onAddRole }) {
  const { table, thead, tbody, tr, th, td, div, span, button } = tags;
  const [expandedCategories, setExpandedCategories] = createSignal(new Set(permissionCategories.map(c => c.id)));

  const toggleCategory = (id) => {
    const expanded = new Set(expandedCategories());
    expanded.has(id) ? expanded.delete(id) : expanded.add(id);
    setExpandedCategories(expanded);
  };

  return div({ class: css('_flex _col _gap4') },
    table({ class: css('_w[full] _border _r2 _overflow[hidden] _bordercollapse[collapse]') },
      thead({},
        tr({ class: css('_bg[var(--surface-raised)]') },
          th({ class: css('_p3 _textleft _textsm _fontmedium _borderB _w[240px]') }, 'Permission'),
          ...roles.map(role =>
            th({ class: css('_p3 _textcenter _textsm _fontmedium _borderB _min-w[100px]') },
              div({ class: css('_flex _col _aic _gap1') },
                span({}, role.name),
                role.custom ? Button({ variant: 'ghost', size: 'xs', onclick: () => {} },
                  icon('edit-2', { size: '10' })
                ) : null
              )
            )
          ),
          th({ class: css('_p3 _borderB _w[60px]') },
            Button({ variant: 'ghost', size: 'sm', onclick: onAddRole },
              icon('plus', { size: '14' })
            )
          )
        )
      ),
      tbody({},
        ...permissionCategories.flatMap(category => [
          // Category header row
          tr({
            class: css('_bg[var(--surface-raised)/50] _cursor[pointer]'),
            onclick: () => toggleCategory(category.id)
          },
            td({ class: css('_p3 _borderB'), colspan: roles.length + 2 },
              div({ class: css('_flex _aic _gap2') },
                icon(expandedCategories().has(category.id) ? 'chevron-down' : 'chevron-right', { size: '14' }),
                span({ class: css('_textsm _fontmedium') }, category.name)
              )
            )
          ),
          // Permission rows within category
          ...(expandedCategories().has(category.id) ? category.permissions.map(perm =>
            tr({ class: css('_hover:bg[var(--surface-raised)/30]') },
              td({ class: css('_p3 _pl8 _borderB') },
                div({ class: css('_flex _aic _gap2') },
                  span({ class: css('_textsm') }, perm.name),
                  perm.description ? Tooltip({ content: perm.description },
                    icon('info', { size: '12', class: css('_fgmuted') })
                  ) : null
                )
              ),
              ...roles.map(role =>
                td({ class: css('_p3 _textcenter _borderB') },
                  Checkbox({
                    checked: values[role.id]?.[perm.id] || false,
                    onChange: (e) => onChange(role.id, perm.id, e.target.checked),
                    disabled: role.locked
                  })
                )
              ),
              td({ class: css('_borderB') })
            )
          ) : [])
        ])
      )
    ),
    // Save/revert actions
    div({ class: css('_flex _aic _gap2 _jce') },
      Button({ variant: 'outline' }, 'Revert changes'),
      Button({}, 'Save permissions')
    )
  );
}

